public class Main {
    static class Shape {
        double area() {
            return 0;
        }

        @Deprecated
        double oldArea() {
            return area();
        }
    }

    static class Square extends Shape {
        private double side;

        Square(double side) {
            this.side = side;
        }

        @Override
        double area() {
            return side * side;
        }
    }

    public static void main(String[] args) {
        Square s = new Square(5);
        System.out.println("Area: " + s.area());
    }
}

